<!DOCTYPE html>\n<html lang="pt-br">\n<head>\n    <meta charset="UTF-8">\n    <title>Editar Veículo</title>\n</head>\n<body>\n    <h1>Editar Veículo</h1>\n    <form action="/atualizarVeiculo" method="POST">\n        <label for="cliente">Cliente:</label>\n        <input type="text" id="cliente" name="cliente" required><br>\n        <label for="placa">Placa:</label>\n        <input type="text" id="placa" name="placa" required><br>\n        <label for="marca">Marca:</label>\n        <input type="text" id="marca" name="marca" required><br>\n        <label for="modelo">Modelo:</label>\n        <input type="text" id="modelo" name="modelo" required><br>\n        <label for="ano">Ano:</label>\n        <input type="number" id="ano" name="ano" required><br>\n        <label for="cor">Cor:</label>\n        <input type="text" id="cor" name="cor" required><br>\n        <label for="observacoes">Observações:</label>\n        <textarea id="observacoes" name="observacoes"></textarea><br>\n        <input type="submit" value="Salvar">\n    </form>\n</body>\n</html>